import{_ as i,o as s,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"141. Clinical Supervision For Allied Health Professionals Not","description":"","frontmatter":{"title":"141. Clinical Supervision For Allied Health Professionals Not","eba":"Mental Health Services 2024-2028","topics":["education-pd"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/education-pd/141-clinical-supervision-for-allied-health-professionals-not.md","filePath":"ebas/mental-health/health-professionals/education-pd/141-clinical-supervision-for-allied-health-professionals-not.md"}'),r={name:"ebas/mental-health/health-professionals/education-pd/141-clinical-supervision-for-allied-health-professionals-not.md"};function a(t,e,l,p,c,d){return s(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_141-clinical-supervision-for-allied-health-professionals-not" tabindex="-1">141. Clinical Supervision For Allied Health Professionals Not <a class="header-anchor" href="#_141-clinical-supervision-for-allied-health-professionals-not" aria-label="Permalink to &quot;141. Clinical Supervision For Allied Health Professionals Not&quot;">​</a></h1><p>LLEWs) Introduction</p><p><strong>141.1</strong> Clinical supervision is an important mechanism to promote the learning, professional development and wellbeing of Allied Health Professionals, and the delivery of safe, high-quality care to consumers of mental health and wellbeing services. Description</p><p><strong>141.2</strong> Clinical supervision is a process of structured professional support and learning in which Employees are assisted to develop their practice through regular time spent in reflective discussion with experienced and knowledgeable colleagues who are adequately trained in providing clinical supervision.</p><p><strong>141.3</strong> Clinical supervision is not a student supervision, line management/operational supervision, a line management tool, counselling, performance management, or a performance review process (and these processes will be conducted separately from clinical supervision). Clinical supervision will not be used as a method of surveillance.</p><p><strong>141.4</strong> Clinical supervision will be guided by the Victorian Allied Health Clinical Supervision Framework (or successor). Entitlement</p><p><strong>141.5</strong> A maximum of two (2) hours per month of clinical supervision is to be offered to all Employees covered by this section of the Agreement in each discipline (including clinical supervisors). Nothing in this clause prevents an Employee from undertaking group supervision where requested by the employee.</p><p><strong>141.6</strong> An Employee may request additional clinical supervision. In deciding whether to approve their request, the Employer will consider the Employee’s reasons for requesting the additional supervision and the Employer’s operational requirements. This clause does not prevent an Employer offering additional clinical supervision on a as needs basis. Supervision arrangements</p><p><strong>141.7</strong> Clinical supervision will be provided by a clinical supervisor of the Employee’s choice, subject to the requirements of this clause, agreement by the proposed supervisor and agreement by the employer. The Employer will not unreasonably refuse to agree. The external source may include existing reciprocal supervision arrangements with other mental health and wellbeing services.</p><p><strong>141.8</strong> All clinical supervisors must have received clinical supervision and undertaken clinical supervision training acceptable to the Employer. 141.9</p><p><strong>(a)</strong> The parties recognise that discipline-specific clinical supervision is considered best practice. It is expected that Social Workers and Occupational Therapists will utilise a discipline-specific clinical supervision option where a suitable option is available. Should a suitable discipline-specific supervisor not be available internally, the employer and employee may agree on an alternative supervision arrangement.</p><p><strong>(b)</strong> Where there are repeated difficulties in providing options internally for discipline- specific supervision under this subclause, the Employer will consider taking steps to increase such options, which may be internal or external. The steps considered</p><p>may include training additional staff to deliver clinical supervision or establishing a reciprocal supervision arrangement with another health service(s).</p><p><strong>141.10</strong> For Employees classified at Grade 4 or below, the supervisor will be of a higher classification to the employee(s) they are supervising, unless:</p><p><strong>(a)</strong> the Employee requests to be supervised by an Employee of their grade and that supervisor is agreed by the Employer to be appropriately skilled and experienced; or</p><p><strong>(b)</strong> the clinical supervision is delivered, by agreement, by an external supervisor not covered by the Agreement.</p><p><strong>141.11</strong> Clinical supervision will not be provided by the Employee’s line manager/supervisor.</p><p><strong>141.12</strong> An Employee may request a change of clinical supervisor at any time.</p><p><strong>141.13</strong> Wherever practicable, supervision will be held in person, however an Employee may request an alternative arrangement.</p><p><strong>141.14</strong> Supervision will occur on rostered time, at a time mutually agreed between the Employee and Employer. Supervision training</p><p><strong>141.15</strong> Where an Employer and Employee agree for the Employee to become a clinical supervisor, the Employee will be provided access to appropriate clinical supervision training before they start delivering clinical supervision. The particular training undertaken will be agreed between the Employee and Employer. The training will be completed on paid time. Requests from Employees to undertake supervision training will be directed to the Employee’s line manager and will be responded to within 14 days. Access to record of clinical supervisors</p><p><strong>141.16</strong> Employers will maintain and make available to Employees a record of trained supervisors who, subject to their availability, are able to provide clinical supervision to Employees.</p>',22)])])}const m=i(r,[["render",a]]);export{u as __pageData,m as default};
